script:
if doc.project:
    project = frappe.get_doc("Project", doc.project)
    doc.cost_center = project.cost_center

for ref in doc.references:
    if ref.reference_doctype == "Purchase Invoice":
        pi = frappe.get_doc("Purchase Invoice", ref.reference_name)
        if pi.workflow_state != "Approved":
            frappe.throw(f"Payment not allowed. Invoice {pi.name} is not approved.")

    if ref.reference_doctype == "Expense Claim":
        ec = frappe.get_doc("Expense Claim", ref.reference_name)
        if ec.workflow_state != "Approved":
            frappe.throw(f"Payment not allowed. Expense Claim {ec.name} is not approved.")

if doc.party_type == "Employee":
    has_ec = any(ref.reference_doctype == "Expense Claim" for ref in doc.references)

    if not has_ec:
        frappe.throw("Reimbursement must be linked to an Expense Claim")

if doc.party_type == "Supplier":
    has_pi = any(ref.reference_doctype == "Purchase Invoice" for ref in doc.references)

    if not has_pi:
        frappe.throw("Supplier payments must be linked to a Purchase Invoice")

has_po = False

for item in doc.items:
    if item.purchase_order:
        has_po = True
        break

if not has_po:
    frappe.throw("Purchase Invoice must be linked to a Purchase Order")
